const fs = require('fs');
const path = require('path');

function removeImportant(content) {
    return content.replace(/!important\s*/g, '');
}

function processFile(filePath) {
    if (path.extname(filePath) === '.css') {
        const content = fs.readFileSync(filePath, 'utf8');
        const newContent = removeImportant(content);
        fs.writeFileSync(filePath, newContent, 'utf8');
    }
}

function walkDir(dir) {
    fs.readdirSync(dir).forEach(file => {
        const fullPath = path.join(dir, file);
        if (fs.statSync(fullPath).isDirectory()) {
            walkDir(fullPath);
        } else {
            processFile(fullPath);
        }
    });
}

const targetDir = process.argv[2] || path.join(__dirname, '..', 'src');
walkDir(targetDir);
console.log('Removed !important from all CSS files in', targetDir);

import { useState, useEffect } from 'react';
import { UserPresenceService } from '../../services/UserPresenceService';

export function userPresence() {
    const [onlineUsers, setOnlineUsers] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
        let isMounted = true;
        setLoading(true);
        UserPresenceService.setup().then(success => {
            if (!isMounted) return;
            if (!success) {
                setError('Failed to initialize presence service');
                setLoading(false);
                return;
            }
            UserPresenceService.getOnlineUsers().then(users => {
                if (!isMounted) return;
                setOnlineUsers(users);
                setLoading(false);
            }).catch(err => {
                if (!isMounted) return;
                setError(err.message || 'Failed to get online users');
                setLoading(false);
            });
            const handlePresenceChange = (users) => {
                if (!isMounted) return;
                setOnlineUsers(users);
            };
            UserPresenceService.addListener(handlePresenceChange);
            return () => {
                UserPresenceService.removeListener(handlePresenceChange);
            };
        }).catch(err => {
            if (!isMounted) return;
            setError(err.message || 'Failed to initialize presence service');
            setLoading(false);
        });
        return () => {
            isMounted = false;
        };
    }, []);

    return { onlineUsers, loading, error };
}

