}

.text-button:hover {
    color: var(--accent-dark);
    text-decoration: underline;
}

.error-message {
    background: var(--danger-bg);
    color: var(--danger);
    padding: 12px;
    border-radius: var(--radius-md);
    font-size: 14px;
    font-weight: 500;
    margin-bottom: 12px;
