}

.success-message {
    background: rgba(56, 161, 105, 0.1);
    color: var(--success);
    padding: 12px;
    border-radius: var(--radius-md);
    font-size: 14px;
    font-weight: 500;
    text-align: center;
    animation: pulse 1.5s infinite;
}

@keyframes pulse {
    0% { opacity: 0.7; }
    50% { opacity: 1; }
    100% { opacity: 0.7; }
}

.login-btn {
    width: 100%;
    padding: 14px;
    background: var(--accent);
    color: var(--text-light);
    border: none;
    border-radius: var(--radius-md);
    font-size: 16px;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s, transform 0.2s, box-shadow 0.2s;
}

.login-btn:hover {
    background: var(--accent-dark);
    transform: translateY(-2px);
    box-shadow: var(--shadow-md);
}

.login-btn:active {
    transform: translateY(0);
    box-shadow: none;
}

.login-btn:disabled {
    opacity: 0.7;
    cursor: not-allowed;
}

.login-loading {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
}

.loading-dot {
    width: 8px;
    height: 8px;
    background: var(--text-light);
    border-radius: 50%;
    animation: loading-dot 1.2s infinite ease-in-out;
}

.loading-dot:nth-child(1) { animation-delay: -0.24s; }
.loading-dot:nth-child(2) { animation-delay: -0.12s; }

@keyframes loading-dot {
    0%, 80%, 100% { transform: scale(0); }
    40% { transform: scale(1); }
}

.login-footer {
    margin-top: 24px;
    text-align: center;
    color: var(--text-secondary);
    font-size: 14px;
    font-weight: 500;
}

.login-notification {
    position: fixed;
    z-index: 9999;
    right: 32px;
    bottom: 32px;
    min-width: 280px;
    max-width: 350px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
    padding: 16px 20px;
    border-radius: var(--radius-md);
    font-size: 15px;
    font-weight: 500;
    box-shadow: var(--shadow-md);
    animation: login-notification-fadein 0.3s;
}

.login-notification.error {
    background: var(--danger-bg);
    color: var(--danger);
    border-left: 5px solid var(--danger);
}

.login-notification.success {
    background: var(--success-bg);
    color: var(--success);
    border-left: 5px solid var(--success);
}

.login-notification-close {
    background: none;
    border: none;
    color: inherit;
    font-size: 22px;
    font-weight: bold;
    cursor: pointer;
    margin-left: 8px;
    line-height: 1;
    padding: 0 4px;
    opacity: 0.7;
    transition: opacity 0.2s;
}

.login-notification-close:hover {
    opacity: 1;
}

@keyframes login-notification-fadein {
    from { opacity: 0; transform: translateY(30px);}
    to { opacity: 1; transform: translateY(0);}
}

@media (max-width: 1024px) {
    .login-container {
        padding-top: 32px;
    }
    .login-wrapper {
        max-width: 900px;
        min-height: 500px;
    }
    .login-info-overlay {
        padding: 32px;
    }
