.mixer-card.plant-card {
    background-color: var(--card-bg);
    border-radius: var(--border-radius-lg);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.05);
    cursor: pointer;
    transition: all 0.3s ease;
    border: 1px solid rgba(0, 0, 0, 0.03);
    height: 100%;
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
}

.mixer-card.plant-card:hover {
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
    transform: translateY(-3px);
    border-color: rgba(49, 130, 206, 0.2);
}

.card-content {
    flex: 1;
    padding: var(--spacing-lg);
    padding-top: calc(var(--spacing-lg) + 4px);
    display: flex;
    flex-direction: column;
}

.card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: var(--spacing-lg);
}

.mixer-name {
    margin: 0;
    font-size: 1.2rem;
    font-weight: 600;
    color: var(--accent);
}

.card-details {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: var(--spacing-md);
}

.detail-row {
    display: flex;
    justify-content: space-between;
    font-size: 0.9rem;
    padding: 4px 0;
    align-items: center;
}

.detail-label {
    color: var(--text-secondary);
    font-weight: 500;
}

.detail-value {
    color: var(--text-primary);
    font-weight: 600;
    text-align: right;
}

.plants-view-container {
    padding: 24px;
    max-width: 1100px;
    margin: 0 auto;
}
.plants-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 16px;
}
.plants-actions {
    display: flex;
    gap: 12px;
}
.plants-search-bar {
    display: flex;
    align-items: center;
    margin-bottom: 16px;
}
.plants-list {
    margin-top: 8px;
}
.plants-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 16px;
}
.plant-card {
    background: var(--background-card, #fff);
    border-radius: 8px;
