import React, { useState } from 'react'

function WeeklyGeneralManagerReportPlugin({
    form,
    allReports,
    weekIso,
    plants = []
}) {
    const [historyWeekIndex, setHistoryWeekIndex] = useState(0)
    const [carouselIndex, setCarouselIndex] = useState(0)
    let historyReports = []
    let historyWeeks = []
    if (Array.isArray(allReports)) {
        historyReports = allReports.filter(r => r.name === 'general_manager' && r.completed)
        historyWeeks = Array.from(new Set(historyReports.map(r => r.week && new Date(r.week).toISOString().slice(0, 10)))).sort((a, b) => new Date(b) - new Date(a))
    }
    let selectedWeekIso = historyWeeks[historyWeekIndex] || weekIso
    let selectedReport = historyReports.find(r => r.week && new Date(r.week).toISOString().slice(0, 10) === selectedWeekIso)
    let selectedForm = selectedReport && selectedReport.data ? selectedReport.data : form
    let displayPlants = plants
    if (!displayPlants || displayPlants.length === 0) {
        if (selectedForm) {
            displayPlants = Object.keys(selectedForm)
                .filter(k => k.startsWith('total_yardage_'))
                .map(k => k.replace('total_yardage_', ''))
                .map(code => ({ plant_code: code }))
        }
    }
    const columns = [
        { key: 'active_operators', label: 'Active Operators' },
        { key: 'runnable_trucks', label: 'Runnable Trucks' },
        { key: 'down_trucks', label: 'Down Trucks' },
        { key: 'new_operators_training', label: 'Operators Training' },
        { key: 'operators_starting', label: 'Operators Starting' },
        { key: 'operators_leaving', label: 'Operators Leaving' }
    ]
    function getValue(code, key) {
        const val = selectedForm[`${key}_${code}`]
        if (val === undefined || val === null || val === '') return '---'
        return val
    }
    return (
        <div style={{ width: '100%', marginTop: 32 }}>
            {historyWeeks.length > 0 && (
                <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', gap: 16, marginBottom: 24 }}>
                    <span style={{ fontWeight: 600, color: 'var(--text-secondary)' }}>View Week:</span>
                    <select
                        value={historyWeekIndex}
                        onChange={e => {
                            setHistoryWeekIndex(Number(e.target.value))
                            setCarouselIndex(0)
                        }}
                        style={{
                            background: 'var(--background)',
                            border: '1.5px solid var(--divider)',
                            borderRadius: 8,
                            fontSize: 15,
                            padding: '6px 14px',
                            color: 'var(--text-primary)',
                            minWidth: 180,
                            boxShadow: '0 1px 4px var(--shadow-xs)',
                            outline: 'none',
                            appearance: 'none'
                        }}
                    >
                        {historyWeeks.map((w, idx) => (
                            <option key={w} value={idx}>
                                {w}
                            </option>
                        ))}
                    </select>
                </div>
            )}
            <div style={{
                width: '100%',
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                marginBottom: 32
            }}>
                <div style={{
                    width: '100%',
                    maxWidth: 900,
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    gap: 0,
                    marginBottom: 18,
                    position: 'relative'
                }}>
                    <button
                        type="button"
                        onClick={() => setCarouselIndex(i => Math.max(i - 1, 0))}
                        disabled={carouselIndex === 0}
                        style={{
                            background: 'var(--accent)',
                            color: 'var(--text-light)',
                            border: 'none',
                            borderRadius: 20,
                            width: 40,
                            height: 40,
                            fontSize: 22,
                            fontWeight: 700,
                            cursor: carouselIndex === 0 ? 'not-allowed' : 'pointer',
                            opacity: carouselIndex === 0 ? 0.5 : 1,
                            marginRight: 18
                        }}
                    >
                        &#8592;
                    </button>
                    <div style={{
                        flex: 1,
                        display: 'flex',
                        justifyContent: 'center',
                        alignItems: 'stretch',
                        gap: 0,
                        width: '100%'
                    }}>
                        {displayPlants.map((plant, idx) => (
                            <div
                                key={plant.plant_code}
                                onClick={() => setCarouselIndex(idx)}
                                style={{
                                    flex: 1,
                                    minWidth: 0,
                                    margin: '0 6px',
                                    background: idx === carouselIndex ? 'var(--accent)' : 'var(--background-elevated)',
                                    color: idx === carouselIndex ? 'var(--text-light)' : 'var(--text-primary)',
                                    borderRadius: 16,
                                    boxShadow: idx === carouselIndex ? '0 2px 12px var(--shadow-sm)' : '0 1px 4px var(--shadow-xs)',
                                    padding: '18px 0',
                                    fontWeight: 700,
                                    fontSize: 18,
                                    letterSpacing: '0.02em',
                                    textAlign: 'center',
                                    border: idx === carouselIndex ? '2px solid var(--accent)' : '2px solid var(--divider)',
                                    cursor: 'pointer',
                                    transition: 'background 0.2s, color 0.2s, border 0.2s'
                                }}
                            >
                                <div style={{ marginBottom: 6, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{plant.plant_name || plant.plant_code}</div>
                                <div style={{ fontWeight: 600, fontSize: 15, color: idx === carouselIndex ? 'var(--text-light)' : 'var(--text-secondary)' }}>
                                    {plant.plant_code}
                                </div>
                            </div>
                        ))}
                    </div>
                    <button
                        type="button"
                        onClick={() => setCarouselIndex(i => Math.min(i + 1, displayPlants.length - 1))}
                        disabled={carouselIndex === displayPlants.length - 1}
                        style={{
                            background: 'var(--accent)',
                            color: 'var(--text-light)',
                            border: 'none',
                            borderRadius: 20,
                            width: 40,
                            height: 40,
                            fontSize: 22,
                            fontWeight: 700,
                            cursor: carouselIndex === displayPlants.length - 1 ? 'not-allowed' : 'pointer',
                            opacity: carouselIndex === displayPlants.length - 1 ? 0.5 : 1,
                            marginLeft: 18
                        }}
                    >
                        &#8594;
                    </button>
                </div>
                {displayPlants[carouselIndex] && (
                    <div style={{
                        width: '100%',
                        maxWidth: 600,
                        margin: '0 auto',
                        background: 'var(--background-elevated)',
                        borderRadius: 18,
                        boxShadow: '0 2px 12px var(--shadow-sm)',
                        padding: '32px 24px',
                        minWidth: 320,
                        marginBottom: 0,
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center'
                    }}>
                        <div style={{
                            fontWeight: 800,
                            fontSize: 22,
                            color: 'var(--accent)',
                            letterSpacing: '0.03em',
                            marginBottom: 18,
                            textAlign: 'center'
                        }}>
                            {displayPlants[carouselIndex].plant_name} ({displayPlants[carouselIndex].plant_code})
                        </div>
                        <div style={{
                            display: 'grid',
                            gridTemplateColumns: '1fr 1fr',
                            gap: 18,
                            width: '100%'
                        }}>
                            {columns.map(col => (
                                <div key={col.key}>
                                    <label style={{ fontWeight: 600, fontSize: 15, marginBottom: 6, display: 'block' }}>
                                        {col.label}
                                    </label>
                                    <input
                                        type="text"
                                        value={getValue(displayPlants[carouselIndex].plant_code, col.key)}
                                        readOnly
                                        disabled
                                        style={{
                                            width: '100%',
                                            fontSize: 16,
                                            padding: '8px 12px',
                                            borderRadius: 8,
                                            border: '1.5px solid var(--divider)',
                                            background: 'var(--background)',
                                            color: 'var(--text-primary)',
                                            fontWeight: 600
                                        }}
                                    />
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
    )
}

export { WeeklyGeneralManagerReportPlugin }

